**Quick 401 Fix (90% of cases) - Copy-paste these changes:**

## 1. **Token Expiry** (Most common culprit)
```js
// WRONG (old way)
const token = localStorage.getItem('token');

// RIGHT - Refresh if expired
const token = getValidToken(); // See function below

function getValidToken() {
  let token = localStorage.getItem('token');
  if (!token) return null;

  const payload = JSON.parse(atob(token.split('.')[1]));
  if (payload.exp * 1000 < Date.now()) {
    // Token expired - refresh it
    return refreshToken();
  }
  return token;
}
```

## 2. **Headers** (Copy this exact format)
```js
// WRONG
headers: { 'Authorization': token }

// RIGHT
headers: {
  'Authorization': `Bearer ${token}`,
  'Content-Type': 'application/json'
}
```

## 3. **Full Working API Call**
```js
async function apiCall() {
  const token = getValidToken();
  if (!token) {
    // Redirect to login
    window.location.href = '/login';
    return;
  }

  try {
    const response = await fetch('/your-api-endpoint', {
      method: 'GET', // or POST
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    });

    if (response.status === 401) {
      // Auto-refresh and retry ONCE
      const newToken = await refreshToken();
      if (newToken) {
        // Retry with new token
        return apiCall();
      }
    }

    if (!response.ok) throw new Error(`HTTP ${response.status}`);

    return await response.json();
  } catch (error) {
    console.error('API failed:', error);
  }
}
```

## 4. **Add Refresh Token**
```js
async function refreshToken() {
  const refreshToken = localStorage.getItem('refreshToken');
  if (!refreshToken) return null;

  try {
    const response = await fetch('/auth/refresh', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ refreshToken })
    });

    if (response.ok) {
      const { token, refreshToken: newRefresh } = await response.json();
      localStorage.setItem('token', token);
      localStorage.setItem('refreshToken', newRefresh);
      return token;
    }
  } catch (e) {
    localStorage.clear();
    window.location.href = '/login';
  }
  return null;
}
```

